"use strict";(self.webpackChunkblogv2_dev=self.webpackChunkblogv2_dev||[]).push([[7925],{9643:(e,t,a)=>{a.r(t),a.d(t,{data:()=>i});const i={key:"v-f47ecbf8",path:"/linux/memory.html",title:"Memory Hierarchy - Cache",lang:"zh-CN",frontmatter:{summary:"Memory Hierarchy - Cache Abstract Introduction 程序员总希望存储是无限的，我们通过一系列的技术手段让程序员产生这种错觉。 本文主要研究存储层次结构中的 cache 环节，本文的行文构成包含如下： 1. 介绍空间局部性原理和时间局部性原理 2. 简单介绍 cache 的基本概念，包括 cache line 各个字段",head:[["meta",{property:"og:url",content:"https://vueblog.weigao.cc/linux/memory.html"}],["meta",{property:"og:site_name",content:"WW"}],["meta",{property:"og:title",content:"Memory Hierarchy - Cache"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-06-15T09:29:14.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-06-15T09:29:14.000Z"}]]},excerpt:"",headers:[{level:2,title:"Abstract",slug:"abstract",children:[{level:3,title:"Introduction",slug:"introduction",children:[]},{level:3,title:"Key Word",slug:"key-word",children:[]},{level:3,title:"temporal locality & spatial locality",slug:"temporal-locality-spatial-locality",children:[]}]},{level:2,title:"Cache Abstract",slug:"cache-abstract",children:[]},{level:2,title:"Cache line",slug:"cache-line",children:[{level:3,title:"tag",slug:"tag",children:[]},{level:3,title:"valid",slug:"valid",children:[]},{level:3,title:"data",slug:"data",children:[]}]},{level:2,title:"hit & miss",slug:"hit-miss",children:[{level:3,title:"Why cache miss?",slug:"why-cache-miss",children:[]},{level:3,title:"Ways to lower miss rate",slug:"ways-to-lower-miss-rate",children:[]},{level:3,title:"hide some transfer time",slug:"hide-some-transfer-time",children:[]},{level:3,title:"Handling cache misses",slug:"handling-cache-misses",children:[]}]},{level:2,title:"cache 映射方式",slug:"cache-映射方式",children:[{level:3,title:"full-associative",slug:"full-associative",children:[]},{level:3,title:"direct-mapped",slug:"direct-mapped",children:[]},{level:3,title:"set-associative",slug:"set-associative",children:[]},{level:3,title:"Summary",slug:"summary",children:[]}]},{level:2,title:"置换策略",slug:"置换策略",children:[]},{level:2,title:"Cache Write",slug:"cache-write",children:[{level:3,title:"Write through",slug:"write-through",children:[]},{level:3,title:"Write buffer",slug:"write-buffer",children:[]},{level:3,title:"Write back: dirty",slug:"write-back-dirty",children:[]},{level:3,title:"Write miss",slug:"write-miss",children:[]}]},{level:2,title:"cache 一致性",slug:"cache-一致性",children:[{level:3,title:"Example",slug:"example",children:[]},{level:3,title:"Write invalidate",slug:"write-invalidate",children:[]},{level:3,title:"Write update",slug:"write-update",children:[]}]},{level:2,title:"cache 一致性协议",slug:"cache-一致性协议",children:[{level:3,title:"MESI",slug:"mesi",children:[]},{level:3,title:"Other MESI",slug:"other-mesi",children:[]}]},{level:2,title:"片内可寻址存储器",slug:"片内可寻址存储器",children:[]},{level:2,title:"Others",slug:"others",children:[{level:3,title:"内存对齐",slug:"内存对齐",children:[]}]},{level:2,title:"Reference",slug:"reference",children:[]}],git:{createdTime:1654659555e3,updatedTime:1655285354e3,contributors:[{name:"weigao chen",email:"weigao_1995@yeah.net",commits:6}]},readingTime:{minutes:16.4,words:4920},filePathRelative:"linux/memory.md"}},8954:(e,t,a)=>{a.r(t),a.d(t,{default:()=>f});var i=a(6252);const r=(0,i.uE)('<h1 id="memory-hierarchy-cache" tabindex="-1"><a class="header-anchor" href="#memory-hierarchy-cache" aria-hidden="true">#</a> Memory Hierarchy - Cache</h1><h2 id="abstract" tabindex="-1"><a class="header-anchor" href="#abstract" aria-hidden="true">#</a> Abstract</h2><h3 id="introduction" tabindex="-1"><a class="header-anchor" href="#introduction" aria-hidden="true">#</a> Introduction</h3><p>程序员总希望存储是无限的，我们通过一系列的技术手段让程序员产生这种错觉。</p><p>本文主要研究存储层次结构中的 cache 环节，本文的行文构成包含如下：</p><ol><li>介绍空间局部性原理和时间局部性原理</li><li>简单介绍 cache 的基本概念，包括 cache line 各个字段的解析</li><li>介绍 cache 的 hit, miss 发生的原因、造成的影响以及可能的解决方案；包括两个重要的算法和通用的处理 cache miss 的方法</li><li>介绍 cache 的几种映射方式和置换策略</li><li>写 cache 相关的技术点，Write miss 相关介绍</li><li>cache 一致性监听协议 MESI(x)</li><li>其他的相关知识</li></ol><h3 id="key-word" tabindex="-1"><a class="header-anchor" href="#key-word" aria-hidden="true">#</a> Key Word</h3><table><thead><tr><th>key word</th><th>means</th><th>comments</th></tr></thead><tbody><tr><td>memory hierarchy</td><td>内存层次结构</td><td></td></tr><tr><td>principle of locality</td><td>局部性原理</td><td></td></tr><tr><td>temporal locality</td><td>时间局部性</td><td></td></tr><tr><td>spatial locality</td><td>空间局部性</td><td></td></tr><tr><td>Locality of reference</td><td>访问局部性</td><td></td></tr></tbody></table><h3 id="temporal-locality-spatial-locality" tabindex="-1"><a class="header-anchor" href="#temporal-locality-spatial-locality" aria-hidden="true">#</a> temporal locality &amp; spatial locality</h3><p>总体而言，可以归纳为访问局部性，其含义是计算机科学领域的应用程序在访问内存的时候，倾向于访问内存中较为靠近的值。</p><p>时间局部性：以 loop 为例, 被引用过一次的存储器位置在未来会被多次引用</p><p>空间局部性：指令是按照顺序执行的；如果一个存储器的位置被引用，那么将来他附近的位置也会被引用，典型的例子就是数组。</p><ul><li><p>存储层次结构如何利用时间局部性和空间局部性？</p><p>主要是 2 个：将经常访问的数据放在距离处理器更近的地方，将多个连续的“块”移动到上层存储中来利用空间局部性。</p><p>接近处理器的存储是比较小和比较快的，除了成本考虑之外，接近处理器的存储比较小的话，其命中率也更高。</p></li><li><p>理解 hit rate, miss rate, hit time, miss penalty</p></li></ul><p>局部性是计算机系统中的一种可预测的行为，系统的这种强访问局部性，可以被用来处理内核的指令流水线中的性能优化，如缓存、分支预测、内存预读取等。</p><h2 id="cache-abstract" tabindex="-1"><a class="header-anchor" href="#cache-abstract" aria-hidden="true">#</a> Cache Abstract</h2><blockquote><p>Caching is perhaps the most important example of the big idea of <strong>prediction</strong>. It relies on the principle of locality to try to find the desired data in the higher levels of the memory hierarchy, and provides mechanisms to ensure that when the prediction is wrong it finds and uses the proper data from the lower levels of the memory hierarchy. The hit rates of the cache prediction on modern computers are often above 95%.</p></blockquote><p>这句话从宏观维度总结了 cache 的一些作用：</p><ul><li>预测大思想的完美应用</li><li>依赖了局部性原理</li></ul><p>其本质就是试图在存储层次结构的更高层次找到想要的数据。</p><h2 id="cache-line" tabindex="-1"><a class="header-anchor" href="#cache-line" aria-hidden="true">#</a> Cache line</h2><p>整个cache 空间被分成了 N 个 line，line 是 cache 交换的最小单位，每个 cache line 通常是 32 byte 或者 64 byte, 对于一个字节我们还需要更加注意，那就是 cache line 包含的内容：</p><table><thead><tr><th style="text-align:center;">———————————–</th><th style="text-align:center;">——————————–</th><th style="text-align:center;">———————————–</th></tr></thead><tbody><tr><td style="text-align:center;">valid</td><td style="text-align:center;">tag</td><td style="text-align:center;">block</td></tr></tbody></table><p>其中 block 表示 cache 中缓存的数据，tag 是该 cache line 对应的内存的地址，valid 表示该 cache line 中的数据是否有效。</p><p>在此再解释一下 tag 和 valid 的作用<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>：</p><h3 id="tag" tabindex="-1"><a class="header-anchor" href="#tag" aria-hidden="true">#</a> tag</h3><blockquote><p>Because each cache location can contain the contents of a number of different memory locations, how do we know whether the data in the cache corresponds to a requested word? That is, how do we know whether a requested word is in the cache or not?</p></blockquote><p>为了解决上述的问题，我们使用了 tag 这个字段，原始的对于 tag 的定义可以如下所示：</p><blockquote><p>A field in a table used for a memory hierarchy that contains the address information required to identify whether the associated block in the hierarchy corresponds to a requested word.</p></blockquote><p>其意思就是说对应了内存中的地址信息。</p><p>不过我们需要注意一个细节，那就是我们如果使用 direct-mapped（❓❓ 目前看来是这样的，这个以后再好好思考一下），那么这个 tag 就是不需要保存完整的地址信息的。</p><h3 id="valid" tabindex="-1"><a class="header-anchor" href="#valid" aria-hidden="true">#</a> valid</h3><blockquote><p>We also need a way to recognize that a cache block does not have valid information. For instance, when a processor starts up, the cache does not have good data, and the tag fields will be meaningless.</p></blockquote><p>valid 的存在是因为我们还需要标识 cache 中的信息是否有效，比如说这边举了一个例子，说的是如果处理器刚刚启动的时候，缓存中的数据肯定是无效的，valid 字段就是起到这样一个作用。</p><h3 id="data" tabindex="-1"><a class="header-anchor" href="#data" aria-hidden="true">#</a> data</h3><p>剩下的是 data 或者 block 块，其实在实际的 cache 中，我们长这样（Intrinsity FastMATH data cache 为例）：</p><table><thead><tr><th>valid</th><th>tag</th><th>block 1</th><th>block 2</th><th>…</th><th>block n</th></tr></thead><tbody><tr><td>8</td><td>18</td><td>32</td><td>32</td><td>…</td><td>32</td></tr></tbody></table><p>在上述的例子中，block 有多个，实际构成了总的 data, 而每个 block 的定位是依靠地址中的某几个字节分配的偏移量决定的，比如我们一共有 16 个 block, 则地址字段需要分配 4 bit 用于表示偏移量，有些英文文档中称作 multiplexor，那么我们每个 cache line(entry) 中可以保存的总的数据量为：32 bit * 16。</p><p>我们举例一个地址字段来说明这个：</p><table><thead><tr><th>31 .. 14</th><th>13 .. 6</th><th>5..2</th><th>1..0</th></tr></thead><tbody><tr><td>tag</td><td>index</td><td>byte offset -&gt; block offset</td><td></td></tr></tbody></table><p>这个例子中的 5..2 bit 就是用作定位偏移得的。</p><blockquote><p>Intrinsity FastMATH data cache 使用了数据 cache 和 指令 cache 分离的设计。</p></blockquote><h2 id="hit-miss" tabindex="-1"><a class="header-anchor" href="#hit-miss" aria-hidden="true">#</a> hit &amp; miss</h2><p>cache hit(命中)：读取时间 X 个 cycle</p><p>cache miss：读取时间 XX 或者 XXX 个 cycle</p><p>所以 hit 和 miss 有很大的性能差距。</p><h3 id="why-cache-miss" tabindex="-1"><a class="header-anchor" href="#why-cache-miss" aria-hidden="true">#</a> Why cache miss?</h3><p>有三种情况会导致 cache misss:</p><ol><li>Compulsory miss, 必须的 miss，如第一次访问程序或者数据时，这些程序或者数据没有在 cache 中</li><li>Capacity miss, cache 容量满了的时候，新数据到来，需要重新搬移，就 miss 了；或者还存在一种情况是 cache 无法包含程序执行期间所需的所有块。</li><li>Conflict miss, 这种情况下，cache 可能还有空闲空间，但是这个地址对应的 cache line 已经被使用了，也会导致 cache miss.</li></ol>',48),c=(0,i.uE)('<h3 id="ways-to-lower-miss-rate" tabindex="-1"><a class="header-anchor" href="#ways-to-lower-miss-rate" aria-hidden="true">#</a> Ways to lower miss rate</h3><h4 id="使用较大的-block" tabindex="-1"><a class="header-anchor" href="#使用较大的-block" aria-hidden="true">#</a> 使用较大的 block</h4><p>较大的 blocks 利用空间局部性原理来降低 miss rate, 通常而言，增加块的大小会降低 miss rate, 但是其存在一个阈值，如果 block 的大小成为缓存很大的一部分，最终 miss rate 反而会上升，这是因为缓存中可以保存的块的数量变少，导致了很多竞争。</p><p>除此之外，使用较大的 blocks 会造成 cache 未命中的时候的代价变大，主要是体现在 cache 加载的时候(fetch the block), 这个过程分为两个部分：<strong>the latency to the first word and the transfer</strong><strong>time for the rest of the block.</strong> 比较好理解，就用英文表述了。通常而言，这个 transfer time 是随着 block 的增加而增加的。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>🧡🧡🧡 我们可以获得一个启发：<strong>如果我们可以设计方法降低较大的 block 的 transfer time, 那么我们就可以进一步改善缓存的性能。</strong></p></div><h3 id="hide-some-transfer-time" tabindex="-1"><a class="header-anchor" href="#hide-some-transfer-time" aria-hidden="true">#</a> hide some transfer time</h3><p>在使用较大的 block 的时候，我们采取一个<strong>隐藏一些传输时间</strong>的方法来减少未命中的惩罚。</p><ul><li>early start</li><li>requested word first or critical word first</li></ul><p>❌❌❌ 后续需要重点研究这两个算法。</p><h3 id="handling-cache-misses" tabindex="-1"><a class="header-anchor" href="#handling-cache-misses" aria-hidden="true">#</a> Handling cache misses</h3><ul><li>缓存处理起来 hit 的工作相比于 miss 是微不足道的。</li><li>cache miss handing 需要处理器控制单元和单独的控制器合作完成，这个单独的控制器启动内存访问、填充缓存</li><li>缓存未命中的处理会导致流水线 stall, 此时需要保存所有寄存器的状态</li><li>缓存未命中（处理指令未命中、处理数据未命中）会导致整个处理器暂停，冻结临时寄存器和程序员可见寄存器的内容，同时等待内存。（注意一下，乱序执行的处理器此时还可以允许执行指令）</li></ul><p>处理缓存 miss 的步骤大概可以总结如下（主要研究指令 miss）：</p><ol><li><p>发送 PC 值到内存</p><p>Since the program counter is incremented in the first clock cycle of execution, the address of <strong>the instruction that generates an instruction cache miss</strong> is equal to the value of the program counter minus 4.</p><p>如何理解 the instruction that generates an instruction cache miss? 其实我们只要了解到，cache miss 以后，PC 寄存器向前走了，所以这时候我们需要向后走去找到这个 miss 的指令的地址，然后再去内存中找，就可以了！</p></li><li><p>控制主存执行读取，并等待内存完成访问</p></li><li><p>写入缓存，将内存中的数据放入缓存的数据部分，tag 写入地址（from ALU）的高位，并打开有效位</p></li><li><p>重启指令的执行，这将重新读取指令，这是在缓存中就可以找到该指令</p></li></ol><h2 id="cache-映射方式" tabindex="-1"><a class="header-anchor" href="#cache-映射方式" aria-hidden="true">#</a> cache 映射方式</h2><p>映射方式主要由以下几种：</p><ol><li>全相联 cachem, full-associative cache</li><li>直接映射 cache, direct-mapped cache</li><li>组相联 cache, set-associative cache</li></ol><h3 id="full-associative" tabindex="-1"><a class="header-anchor" href="#full-associative" aria-hidden="true">#</a> full-associative</h3><p>悲剧的被比较对象，性能很烂，我们现在不研究这个。</p><p>但是这种方式有个优点就是内存中的每个 line(注意到内存中是块存储的，为了方便理解这里也说得 line) 可以映射到任意的 cache line 中，从这个角度看，full-associate 效率更好，但是其查找过于复杂。</p><p>🧡🧡 言外之意在于，优秀的查找算法前提下，这种方式还是可以应用的。</p><h3 id="direct-mapped" tabindex="-1"><a class="header-anchor" href="#direct-mapped" aria-hidden="true">#</a> direct-mapped</h3><p>主要的思想是把内存分为 N 个page, 每一个 page 的大小和 cache 相同，page 中的 line0 只能映射到 cache 中的 line0, 以此类推。</p><h3 id="set-associative" tabindex="-1"><a class="header-anchor" href="#set-associative" aria-hidden="true">#</a> set-associative</h3><p>direvt-mapped 的方式是处理器上比较常用的，但是在某些特定的情况下会存在很大的缺陷，所以现代的商用处理器都是用 set-associative cache 来解决这个问题，这也是我们这节要研究的。</p><p>set-associative 将 cache 分成了多个 way, <code>direvt-mapped == 1 way set-associative</code>， 使用多少个 cache way 也是一种权衡的结果。</p><p>举例，以下是四路组相联的结构（一路是直接映射）：</p><table><thead><tr><th style="text-align:center;">set</th><th>tag</th><th>data</th><th>tag</th><th>data</th><th>tag</th><th>data</th><th>tag</th><th>data</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr><tr><td style="text-align:center;">1</td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h3><p>三种方式的对比：</p><table><thead><tr><th style="text-align:center;">机制</th><th style="text-align:center;">组的数量</th><th style="text-align:center;">每组中块的数量</th></tr></thead><tbody><tr><td style="text-align:center;">全相联</td><td style="text-align:center;">1</td><td style="text-align:center;">cache 中块的数量</td></tr><tr><td style="text-align:center;">直接映射</td><td style="text-align:center;">cache 中块的数量</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">组相联</td><td style="text-align:center;">cache 中块的数量 / 相联度</td><td style="text-align:center;">相联度（通常2~16）</td></tr></tbody></table><p>增加相联度的好处通常是降低失效率，失效率的改进来自于减少对于同一位置的竞争而产生的失效。</p><p>三种方式进行查找的对比：</p><table><thead><tr><th style="text-align:center;">机制</th><th style="text-align:center;">定位方法</th><th style="text-align:center;">需要比较的次数</th></tr></thead><tbody><tr><td style="text-align:center;">全相联</td><td style="text-align:center;">查找所有cache 表项</td><td style="text-align:center;">cache 容量</td></tr><tr><td style="text-align:center;"></td><td style="text-align:center;">独立的查找表</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:center;">直接映射</td><td style="text-align:center;">索引</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">组相联</td><td style="text-align:center;">索引组，组中的元素</td><td style="text-align:center;">相联度</td></tr></tbody></table><h2 id="置换策略" tabindex="-1"><a class="header-anchor" href="#置换策略" aria-hidden="true">#</a> 置换策略</h2><ol><li>随机</li><li>FIFO 先进先出</li><li>LRU 最近最少使用</li></ol><p>LRU 我们使用的最多，并且性能也最好。</p><p>关于替换策略的选择，也有一些考量在里面，并不是 LRU 就一定是最好的，我们举例说明：</p><ul><li>在相联度不低（2，4）的层次结构中实现 LRU 的代价太高，所以一般使用近似实现</li><li>随着 cache 容量变大，两种替换策略的性能差异也逐渐缩小</li><li>在虚拟存储中，使用 LRU 是因为失效代价很大，失效率的微小降低都显得十分重要；并且其失效相对不那么频繁发生，LRU 也可以由软件近似实现</li></ul><h2 id="cache-write" tabindex="-1"><a class="header-anchor" href="#cache-write" aria-hidden="true">#</a> Cache Write</h2><p>所谓 cache 写，指的就是 cpu 修改了 cache 中的数据的时候，内存的数据也要随之改变。为了达到这个目的，cache 提供了几种写策略：</p><ol><li>Write through</li><li>Write buffer</li><li>Write back</li></ol><h3 id="write-through" tabindex="-1"><a class="header-anchor" href="#write-through" aria-hidden="true">#</a> Write through</h3><p>核心策略：每次 CPU 修改了 cache 中的内容，cache 立即更新（cache 控制器）内存中的内容。</p><p>这种方式会有大量写内存的操作，所以效率较低。</p><h3 id="write-buffer" tabindex="-1"><a class="header-anchor" href="#write-buffer" aria-hidden="true">#</a> Write buffer</h3><blockquote><p>A queue that holds data while the data are waiting to be written to memory.</p></blockquote><p>Write buffer 中保存了准备写入内存的数据，处理器同时写入 cache 和 write buffer, 而在写入主存完成后，write buffer 中的数据就 free 掉了。</p><p>这种方法的缺点在于，如果这个 write buffer 已经满了，那么处理器来写这个的时候必须停止，等待 write buffer 中出现新的空位。</p><p>这个之中还有一个矛盾在于，如果处理器生成写入的速率大于内存可以完成的写入速率，那么拿什么 write buffer 都不会起作用的。</p><h3 id="write-back-dirty" tabindex="-1"><a class="header-anchor" href="#write-back-dirty" aria-hidden="true">#</a> Write back: dirty</h3><p>核心策略：CPU 或者内核修改了 cache 中的内容的时候，cache 不会立即更新内存内容，而是等到这个 cache line 因为某种原因需要从 cache 中移除的时候，cache 才去更新内存中的内容。</p><p>cache 为了知道某个 line 的内容有没有被修改，于是增加了一个新的标志位：<strong>dirty</strong>, 增加以后的 cache line 结构如下所示：</p><table><thead><tr><th>dirty</th><th>valid</th><th>tag</th><th>block</th></tr></thead></table><p>具体的 dirty 的用法如下：</p><ul><li>dirty 位为 1, 表示这个数据已经被修改</li><li>dirty 位为 0, 表示这个数据和内存中的数据是一致的</li></ul><p>程序 cache 不需要 dirty 标志位，数据 cache 需要 dirty 标志位。</p><p>几个特点：</p><blockquote><p>By comparison, in a write-through cache, writes can always be done in one cycle.</p></blockquote><p>很多 write back 策略还包括着 write buffer 用于在 miss 的时候减少 miss 惩罚，是这么做的：修改后的块被移动到 write buffer 中，Assuming another miss does not occur immediately, this technique halves the miss penalty when a dirty block must be replaced.</p><h3 id="write-miss" tabindex="-1"><a class="header-anchor" href="#write-miss" aria-hidden="true">#</a> Write miss</h3><p>Write miss 这个第一眼看过去似乎是比较奇特的，写也会 Miss 吗？当然会了，这里的写 miss 指的是没有写在缓存里面。</p><p>考虑 write through 场景下的一个 write miss, 在 write through 中，有两种策略：</p><ol><li><p>write allocate</p><p>在缓存中分配一个 block, 然后用内存中的 block 覆盖之。</p></li><li><p>no write allocate</p><p>更新内存中的 block, 但是不放入 cache 中。这种场景可能适用于计算机清零某一页的内容这样的情况，有些计算机是允许按页更改写入分配策略的。</p></li></ol><h2 id="cache-一致性" tabindex="-1"><a class="header-anchor" href="#cache-一致性" aria-hidden="true">#</a> cache 一致性</h2><h3 id="example" tabindex="-1"><a class="header-anchor" href="#example" aria-hidden="true">#</a> Example</h3><p>定义：主要体现在不同 core 的 cache 中数据不同。</p><pre><code>-----------------------------------------\n|       多核处理器                       |\n| -----------------   ----------------  |\n| |     core 0     |  |     core 1    | |\n| |  cache 0(x = 3)|  | cache 1(x = 5)| |\n| ------------------  ----------------- |\n|-------------------------------------- |\n\n\t------------------------------\n\t|     memory (x = 3)          |\n\t|                             |\n\t-------------------------------\n</code></pre><p>core 0 和 core 1 中的 x 容易出现数据不一致的情况，比如 core 0 将 x 进行了修改，但是 core 1 不知道 x 已经被修改了，还在使用旧值，这样就会导致数据不一致的问题。</p><p>处理器提供了两个操作来保证 cache 的一致性：</p><ol><li>Wirte invalidate</li><li>Write update</li></ol><h3 id="write-invalidate" tabindex="-1"><a class="header-anchor" href="#write-invalidate" aria-hidden="true">#</a> Write invalidate</h3><p>置无效，其核心思想为：当一个 core 修改了一份数据，其他 core 上如果有这份数据的复制，就置为无效。</p><p>这种方法的优点在于，比较简单，而且无效标志位 valid 在 cache line 中有对应的字段，这意味着置无效就是把 cache 的一个 line 直接写为无效了，这个 cache line 中其他有效的数据也不能被使用了。</p><p>大部分处理器都使用这个操作。</p><h3 id="write-update" tabindex="-1"><a class="header-anchor" href="#write-update" aria-hidden="true">#</a> Write update</h3><p>写更新：当一个内核修改了一份数据，其他的地方如果有这份数据的赋值，就更新到最新值。</p><p>其缺点是会产生频繁的更新动作。</p><h2 id="cache-一致性协议" tabindex="-1"><a class="header-anchor" href="#cache-一致性协议" aria-hidden="true">#</a> cache 一致性协议</h2><h3 id="mesi" tabindex="-1"><a class="header-anchor" href="#mesi" aria-hidden="true">#</a> MESI</h3><p>主要研究基于 Write invalidate 的一致性协议。比较经典的协议就是 MESI 协议。</p><p>复习一下：cache line 中有两个字段是 dirty 和 valid, 分别表示数据是否被修改和数据是否有效。但是在多核处理器中，多个核会存在共享数据的情况，MESI 协议就可以描述这种共享状态。</p><p>MESI 协议中有 2 bit 用于 cache line 的状态位，如下表：</p><table><thead><tr><th>状态</th><th>全程</th><th>描述</th></tr></thead><tbody><tr><td>M</td><td>Modified</td><td>这行数据被修改了，和内存中的数据不一致</td></tr><tr><td>E</td><td>Exclusive</td><td>这行数据有效，数据和内存中一致，数据只存在于本 core 的 cache 中</td></tr><tr><td>S</td><td>Shared</td><td>这行数据有效，数据和内存中一致，数据存在于很多 cache 中</td></tr><tr><td>I</td><td>Invalid</td><td>这行数据无效</td></tr></tbody></table><p>M 和 E 需要重点理解一下，很明显这四个状态是互斥的，也就是说：</p><ul><li>状态为 M 的时候，这行数据是 dirty 的，但是数据是这个 cache 独有的。除了这个 M 意外，其他的状态下数据都是 clean 的（无效状态是无效的）</li><li>状态位 E 的时候，这行数据是 clean 的，并且数据是这个 cache 独有的</li><li>状态位 S 的时候，这行数据是 clean 的，cache 可以从其他 cache 处同步数据，也可以从内存处同步，协议对此没有做任何要求。</li></ul><p>在 MESI 协议中，<strong>cache 控制器</strong>是可以监听 snoop 其他的 cache 的读写操作。</p><h3 id="other-mesi" tabindex="-1"><a class="header-anchor" href="#other-mesi" aria-hidden="true">#</a> Other MESI</h3><p>AMD 演化了 MOESI 协议，多了一个 O 状态，这个状态是 S 和 M 状态的一种合体，表示本 cache line 中的数据和内存中的数据不一致，不过其他的核可以有这份数据的复制，复制了这份数据的核的这行 cache 的状态为 S.</p><p>Intel I7 演化了 MESIF 协议，多的 F 状态表示 Forward, 其含义是可以把数据直接传给其他内核的 cache, 而 shared 则不能。</p><p>MESIX 统一都可以称为监听协议(snoop)，监听协议的缺点在于沟通成本很高，所以有一种集中管理的目录协议，可以后续研究。</p><h2 id="片内可寻址存储器" tabindex="-1"><a class="header-anchor" href="#片内可寻址存储器" aria-hidden="true">#</a> 片内可寻址存储器</h2><p>通常而言，cache 对用户（程序员）是透明的，但是在 DSP 等性能要求很高的处理器中，处理器存储的一部分作为 cache, 另一部分作为可寻址寄存器，程序员可以直接访问这部分空间。</p><p>这种在做法可以有效地控制 cache miss, 所以我们也称片内可寻址寄存器为：<strong>软件管理的 cache</strong>.</p><p>片内可寻址寄存器的应用：一般而言，cache 是等到 CPU 要使用数据的时候，才从内存中去拿数据的，片内可寻址寄存器可以通过软件控制 DMA，将以后需要的数据提前搬到处理器内部，这就节省了很多 CPU 的等待时间。DMA 是专门负责数据搬移的模块。</p><p>为什么会是软件去做这件事呢？因为程序是可以知道 CPU 什么时候将要访问数据的，而 cache 不知道。但是这种方法对软件的编写难度造成了很大的挑战。</p><h2 id="others" tabindex="-1"><a class="header-anchor" href="#others" aria-hidden="true">#</a> Others</h2><h3 id="内存对齐" tabindex="-1"><a class="header-anchor" href="#内存对齐" aria-hidden="true">#</a> 内存对齐</h3><p>为什么要内存对齐(memory memory)<sup class="footnote-ref"><a href="#footnote2">[2]</a><a class="footnote-anchor" id="footnote-ref2"></a></sup>：</p><ol><li>平台原因：不是所有的硬件平台都可以访问任意地址上的任意数据，某些平台只能在特定的地址处取某些特定类型的数据，否则抛出硬件异常。</li><li>性能原因：如果访问未对齐的内存，处理器需要两次访存操作；而对齐的内存只需要一次访存操作。</li></ol><h2 id="reference" tabindex="-1"><a class="header-anchor" href="#reference" aria-hidden="true">#</a> Reference</h2><hr class="footnotes-sep">',101),l={class:"footnotes"},h={class:"footnotes-list"},d=(0,i._)("li",{id:"footnote1",class:"footnote-item"},[(0,i._)("p",null,[(0,i.Uk)("Computer Organization and Design_ The Hardware Software Interface_ ARM Edition "),(0,i._)("a",{href:"#footnote-ref1",class:"footnote-backref"},"↩︎")])],-1),s={id:"footnote2",class:"footnote-item"},n={href:"https://cloud.tencent.com/developer/article/1727794",target:"_blank",rel:"noopener noreferrer"},o=(0,i.Uk)("一文轻松理解内存对齐"),p=(0,i.Uk)(),u=(0,i._)("a",{href:"#footnote-ref2",class:"footnote-backref"},"↩︎",-1),m={},f=(0,a(3744).Z)(m,[["render",function(e,t){const a=(0,i.up)("Mermaid"),m=(0,i.up)("ExternalLinkIcon");return(0,i.wg)(),(0,i.iD)("div",null,[r,(0,i.Wm)(a,{id:"mermaid-64a55fb0",code:"flowchart%20LR%0A%091(3C)%0A%091.1(Compulsory%20miss%2C%20%E5%BC%BA%E5%88%B6%E5%A4%B1%E6%95%88)%0A%091.2(Capacity%20miss%2C%20%E5%AE%B9%E9%87%8F%E5%A4%B1%E6%95%88)%0A%091.3(Conflict%20miss%2C%20%E5%86%B2%E7%AA%81%E5%A4%B1%E6%95%88)%0A%091%20--%3E%201.1%20%26%201.2%20%26%201.3%0A%091.2.1(%E5%A2%9E%E5%8A%A0cache)%0A%091.2%20-.-%201.2.1%0A"}),c,(0,i._)("section",l,[(0,i._)("ol",h,[d,(0,i._)("li",s,[(0,i._)("p",null,[(0,i._)("a",n,[o,(0,i.Wm)(m)]),p,u])])])])])}]])},3744:(e,t)=>{t.Z=(e,t)=>{const a=e.__vccOpts||e;for(const[e,i]of t)a[e]=i;return a}}}]);